import theme from "../utils/theme"

export default class LightDarkMode extends HTMLElement {
  static get observedAttributes() {
    return ['mode'];
  }

  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    shadowRoot.innerHTML = `
      <style>
        * { 
          margin: 0;
          padding: 0;
          border: 0;
          background: transparent;
          box-sizing: border-box;
          font-family: var(--font-family);
        }
        button {
          display: flex;
          flex-direction: row;
          align-items: center;
          justify-content: flex-end;
          gap: 8px;
          cursor: pointer;
        }
        #toggle {
          height: 40px;
          width: 100px;
          background-color: var(--background-primary);
          display: flex;
          align-items: center;
          justify-content: space-between;
          border-radius: 500px;
          padding: 0px 10px;
        }
        #light-dark-mode-text {
          font-size: 14px;
          font-weight: 400;
          display: inline-block;
          max-width: min-content;
          text-align: left;
          color: var(--text-primary);
        }
        .container {
          border-radius: 500px;
          display: flex;
          align-items: center;
          justify-content: center;
          height: 30px;
          width: 30px;
          --fill: var(--text-primary);
        }
        .active {
          background-color: var(--text-primary);
          --fill: var(--background-primary);
        }
      </style>
      <button aria-labelledby="light-dark-mode-text">
        <span id="toggle">
          <span id="light" class="container active">
            <huanlin-icon name="sun"></huanlin-icon>
          </span>
          <span id="dark" class="container">
            <huanlin-icon name="moon"></huanlin-icon>
          </span>
        </span>
        <span id="light-dark-mode-text">Light mode</span>
      </button>
    `
  }

  handleModeChange = e => {
    const mode = this.getAttribute('mode')
    if (mode === "light") {
      this.setAttribute("mode", "dark")
      theme.setColorScheme("dark")
    } else {
      this.setAttribute("mode", "light")
      theme.setColorScheme("light")
    }
  }
  connectedCallback() {
    this.classList.add("hydrated")
    this.render();
    this.shadowRoot.querySelector("button").addEventListener("click", this.handleModeChange)
  }
  disconnectedCallback() {
    this.shadowRoot.querySelector("button").removeEventListener("click", this.handleModeChange)
  }

  attributeChangedCallback(name, oldValue, newValue) {
    this.render();
  }

  setMode(mode) {
    this.shadowRoot.querySelector('#light-dark-mode-text').innerHTML = mode === "light" ? "Light Mode" : "Dark Mode"
    if (mode === "light") {
      this.shadowRoot.querySelector('#light').classList.add("active")
      this.shadowRoot.querySelector('#dark').classList.remove("active")
    } else {
      this.shadowRoot.querySelector('#dark').classList.add("active")
      this.shadowRoot.querySelector('#light').classList.remove("active")
    }
  }

  render() {
    const mode = this.getAttribute('mode') || 'light';
    this.setMode(mode)
  }
}
